import os, json
def get_files(root_dir):
    ignore_dirs = {'node_modules', '.git', 'dist', 'build', '__pycache__', '.next', 'coverage', 'venv', 'env'}
    ignore_exts = {'.png', '.jpg', '.jpeg', '.gif', '.ico', '.svg', '.mp4', '.mp3', '.wav', '.zip', '.tar', '.gz', '.pdf', '.lock', '.pyc'}
    result = []
    for dirpath, dirnames, filenames in os.walk(root_dir):
        dirnames[:] = [d for d in dirnames if d not in ignore_dirs]
        for f in filenames:
            ext = os.path.splitext(f)[1].lower()
            if ext not in ignore_exts:
                result.append(os.path.join(dirpath, f).replace('\\', '/'))
    return result
print(json.dumps(get_files(r"{{caller.workspace}}")))

