function App() {
  const [workspace, setWorkspace] = useVar('workspace', '');
  const [model, setModel] = useVar('model', 'balanced');
  const [messages, setMessages] = useVar('messages', []);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [status, setStatus] = useState('');
  const [progress, setProgress] = useState(0);

  // ── Index Workspace ──
  const handleIndex = async () => {
    if (!workspace) return alert('Enter a workspace path');
    try {
      setStatus('Setting up database...');
      setProgress(5);
      await stuard.callNode('setup_db');

      setStatus('Scanning files...');
      setProgress(10);
      const scanRes = await stuard.callNode('scan_files', { workspace });
      if (!scanRes.ok) throw new Error('Scan failed');
      const files = JSON.parse(scanRes.stdout);
      if (!files.length) { setStatus('No files found.'); return; }

      await stuard.callNode('clear_index', { workspace });

      let done = 0;
      for (const file of files) {
        setStatus(`Reading ${file.split('/').pop()}...`);
        const readRes = await stuard.callNode('read_chunk', { filePath: file });
        if (!readRes.ok || !readRes.content || readRes.content.length > 100000) { done++; continue; }

        const chunks = readRes.content.match(/.{1,4000}/gs) || [];
        for (let i = 0; i < chunks.length; i++) {
          setStatus(`Embedding ${file.split('/').pop()} (${i+1}/${chunks.length})...`);
          const emb = await stuard.callNode('embed_chunk', { text: chunks[i] });
          if (emb.ok && emb.embedding) {
            await stuard.callNode('store_embedding', {
              id: `${file}_${i}`, path: file, content: chunks[i],
              embedding: JSON.stringify(emb.embedding)
            });
          }
        }
        done++;
        setProgress(10 + Math.floor((done / files.length) * 90));
      }
      setStatus('Done!'); setTimeout(() => { setStatus(''); setProgress(0); }, 3000);
    } catch (err) { setStatus(`Error: ${err.message}`); }
  };

  // ── Cosine similarity ──
  const cosine = (a, b) => {
    let dot = 0, nA = 0, nB = 0;
    for (let i = 0; i < a.length; i++) { dot += a[i]*b[i]; nA += a[i]*a[i]; nB += b[i]*b[i]; }
    return dot / (Math.sqrt(nA) * Math.sqrt(nB));
  };

  // ── Chat ──
  const handleSend = async () => {
    if (!input.trim() || isLoading) return;
    const newMsgs = [...messages, { role: 'user', content: input }];
    setMessages(newMsgs);
    setInput('');
    setIsLoading(true);
    try {
      setStatus('Searching codebase...');
      const qEmb = await stuard.callNode('semantic_search', { query: input });
      let snippets = '';
      if (qEmb.ok && qEmb.embedding) {
        const db = await stuard.callNode('fetch_all_embeddings');
        if (db.ok && db.results) {
          const scored = db.results.map(r => ({
            path: r.path, content: r.content,
            score: cosine(qEmb.embedding, JSON.parse(r.embedding))
          })).sort((a,b) => b.score - a.score).slice(0, 5);
          snippets = scored.map(s => `--- ${s.path} (${(s.score*100).toFixed(1)}%) ---\n${s.content}`).join('\n\n');
        }
      }
      setStatus('Agent thinking...');
      const res = await stuard.callNode('agent_think', {
        prompt: `You are an expert AI coding assistant.\nWorkspace: ${workspace}\n\nRelevant code:\n${snippets}\n\nRequest: ${input}`,
        context: JSON.stringify(newMsgs.slice(0, -1)),
        model
      });
      setMessages([...newMsgs, { role: 'assistant', content: res.ok ? res.text : `Error: ${res.error}` }]);
    } catch (err) {
      setMessages([...newMsgs, { role: 'assistant', content: `Error: ${err.message}` }]);
    } finally { setIsLoading(false); setStatus(''); }
  };

  return (
    <div className=\"flex h-screen bg-slate-900 text-slate-300 font-sans\">
      <div className=\"w-72 bg-slate-950 p-4 flex flex-col border-r border-slate-800\">
        <h1 className=\"text-xl font-bold text-white mb-6 flex items-center gap-2\"><span className=\"text-blue-500\">⚡</span> Custom Cursor</h1>
        <div className=\"mb-6\">
          <label className=\"block text-xs font-semibold text-slate-500 uppercase mb-2\">Workspace</label>
          <input value={workspace} onChange={e => setWorkspace(e.target.value)} placeholder=\"C:/path/to/project\" className=\"w-full bg-slate-800 border border-slate-700 rounded p-2 text-sm text-white focus:border-blue-500 outline-none\" />
          <button onClick={handleIndex} disabled={!!status} className=\"mt-2 w-full bg-blue-600 hover:bg-blue-500 disabled:bg-slate-800 disabled:text-slate-500 text-white text-sm py-2 rounded\">Build Index</button>
          {status && <div className=\"mt-3\"><div className=\"text-xs text-blue-400 mb-1 truncate\">{status}</div>{progress > 0 && <div className=\"w-full bg-slate-800 rounded-full h-1.5\"><div className=\"bg-blue-500 h-1.5 rounded-full transition-all\" style={{width:`${progress}%`}} /></div>}</div>}
        </div>
        <div className=\"mb-6\">
          <label className=\"block text-xs font-semibold text-slate-500 uppercase mb-2\">Model</label>
          <select value={model} onChange={e => setModel(e.target.value)} className=\"w-full bg-slate-800 border border-slate-700 rounded p-2 text-sm text-white outline-none\">
            <option value=\"fast\">Fast</option><option value=\"balanced\">Balanced</option><option value=\"smart\">Smart</option>
          </select>
        </div>
        <button onClick={() => setMessages([])} className=\"mt-auto w-full text-slate-500 hover:text-white text-sm py-2\">Clear</button>
      </div>
      <div className=\"flex-1 flex flex-col\">
        <div className=\"flex-1 overflow-y-auto p-6 space-y-6\">
          {messages.length === 0 ? <div className=\"h-full flex flex-col items-center justify-center text-slate-500\"><div className=\"text-4xl mb-4\">🧠</div><p>Semantic index + node-routed tools</p></div> : messages.map((m,i) => <div key={i} className={`flex ${m.role==='user'?'justify-end':'justify-start'}`}><div className={`max-w-[80%] rounded-lg p-4 ${m.role==='user'?'bg-blue-600 text-white':'bg-slate-800 text-slate-200 border border-slate-700'}`}><div className=\"text-xs opacity-50 mb-1 uppercase\">{m.role}</div><div className=\"whitespace-pre-wrap font-mono text-sm\">{m.content}</div></div></div>)}
          {isLoading && <div className=\"flex justify-start\"><div className=\"bg-slate-800 border border-slate-700 rounded-lg p-4 text-slate-400 flex items-center gap-2\"><div className=\"animate-spin h-4 w-4 border-2 border-blue-500 border-t-transparent rounded-full\" />{status || 'Thinking...'}</div></div>}
        </div>
        <div className=\"p-4 border-t border-slate-800\">
          <div className=\"relative max-w-4xl mx-auto\">
            <textarea value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => { if (e.key==='Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); } }} placeholder=\"Ask about your codebase...\" className=\"w-full bg-slate-800 border border-slate-700 rounded-lg pl-4 pr-12 py-3 text-white focus:border-blue-500 outline-none resize-none h-14\" />
            <button onClick={handleSend} disabled={isLoading || !input.trim()} className=\"absolute right-2 top-2 bottom-2 bg-blue-600 hover:bg-blue-500 disabled:bg-slate-700 text-white rounded px-3 flex items-center\">➤</button>
          </div>
        </div>
      </div>
    </div>
  );
}
